import React, { useState, useEffect } from "react";
import MapView from "../components/MapView";
import CameraCapture from "../components/CameraCapture";
import { io } from "socket.io-client";
import "./journey.css";

const socket = io("http://localhost:5000");

function Journey() {
  const [originCoords, setOriginCoords] = useState(null);
  const [destinationCoords, setDestinationCoords] = useState(null);
  const [info, setInfo] = useState(null);
  const [capturedImage, setCapturedImage] = useState(null);

  // 🔥 NEW STATES
  const [currentAddress, setCurrentAddress] = useState("");
  const [destAddress, setDestAddress] = useState("");

  /* 🔍 GET ADDRESS FROM COORDS */
  const getAddress = async (lat, lng, setFunc) => {
    try {
      const res = await fetch(
        `https://nominatim.openstreetmap.org/reverse?format=json&lat=${lat}&lon=${lng}`
      );
      const data = await res.json();
      setFunc(data.display_name);
    } catch (err) {
      console.log(err);
    }
  };

  /* 📍 LOCATION */
  useEffect(() => {
    const watchId = navigator.geolocation.watchPosition(
      (pos) => {
        const lat = pos.coords.latitude;
        const lon = pos.coords.longitude;

        setOriginCoords({ lat, lng: lon });

        // ✅ address fetch
        getAddress(lat, lon, setCurrentAddress);

        fetch("http://localhost:5000/location", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ lat, lon }),
        });

        socket.emit("location", { lat, lon });
      }
    );

    return () => navigator.geolocation.clearWatch(watchId);
  }, []);

  /* 🎯 SEARCH CONNECT */
  useEffect(() => {
    window.setDestinationFromSearch = (coords) => {
      setDestinationCoords(coords);

      // ✅ destination address
      getAddress(coords.lat, coords.lng, setDestAddress);
    };
  }, []);

  /* 📷 CAMERA */
  const handleCapture = async (img) => {
    setCapturedImage(img);

    await fetch("http://localhost:5000/upload", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({ image: img }),
    });
  };

  /* 🚨 SOS */
  const triggerEmergency = async () => {
    if (!originCoords) return;

    await fetch("http://localhost:5000/sos", {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        lat: originCoords.lat,
        lon: originCoords.lng,
        image: capturedImage,
      }),
    });

    alert("🚨 SOS Sent");
  };

  return (
    <div className="app">

      {/* HEADER */}
      <div className="header-card glass">
        <h2>🛡️ Women Safety Monitor</h2>
      </div>

      {/* CAMERA */}
      <div className="section-card glass">
        <CameraCapture onCapture={handleCapture} />
      </div>

      {/* MAP */}
      <div className="map-wrap glass">
        <MapView
          origin={originCoords}
          destination={destinationCoords}
          setInfo={setInfo}
        />
      </div>

      {/* 📊 ROUTE INFO */}
      <div className="section-card glass">
        <p>🚗 Distance: {info?.distance || "--"} km</p>
        <p>⏱ Time: {info?.time || "--"} min</p>
      </div>

      {/* 📍 LOCATION DETAILS (NEW) */}
      <div className="section-card glass">
        <h3>📍 Journey Details</h3>

        <p>
          <strong>Current:</strong><br />
          {currentAddress || "Fetching..."}
        </p>

        <p>
          <strong>Destination:</strong><br />
          {destAddress || "Not selected"}
        </p>
      </div>

      {/* 🚨 SOS */}
      <button className="sos-btn" onClick={triggerEmergency}>
        🚨 SOS
      </button>

      {/* HELP PAGE */}
      <button onClick={() => (window.location.href = "/help")}>
        🚨 Help Page
      </button>

    </div>
  );
}

export default Journey;
